const prompt = $input.first().json.prompt;
const imageUrl = $('Webhook').first().json.body.url;

return [{
  json: {
    kieBody: JSON.stringify({
      model: "gpt-image-2-image-to-image",
      input: {
        prompt: prompt,
        input_urls: [imageUrl.replace('/upload/', '/upload/f_jpg,q_90/').replace(/\.[^.]+$/, '.jpg')],
        aspect_ratio: "1:1"
      }
    })
  }
}];

const data = $input.item.json.data;
const parsed = data.resultJson ? JSON.parse(data.resultJson) : {};
const imageUrl = parsed.resultUrls?.[0] || null;
return [{
  json: {
    isReady: !!imageUrl,
    enhanced_image_url: imageUrl
  }
}];

const prompt = $input.first().json.prompt;
const imageUrl = $input.first().json.image_url;
return [{
  json: {
    kieBody: JSON.stringify({
      model: "gpt-image-2-image-to-image",
      input: {
        prompt: prompt,
        input_urls: [imageUrl],
        aspect_ratio: "1:1",
        image_count: 1,
        resolution: "1K"
      }
    })
  }
}];

const data = $input.item.json.data;

const parsed = JSON.parse(data.resultJson);
const imageUrl = parsed.resultUrls?.[0] || null;

return [{
  json: {
    isReady: !!imageUrl,
    enhanced_image_url: imageUrl
  }
}];
